const BrokerageKPIFilter: React.FC<{
  shipments: Shipment[];
  activeFilters: any;
  onFilterChange: (key: string, value: any) => void;
}> = ({ shipments, activeFilters, onFilterChange }) => {
  const analysts = useMemo(() => {
    const set = new Set(
      shipments.map((s) => s.technicianResponsibleBrazil).filter(Boolean),
    );
    const toTitleCase = (str: string) =>
      str.replace(
        /\w\S*/g,
        (txt) => txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase(),
      );
    const formatted = Array.from(set).map((s) => toTitleCase(s as string));
    return ['All', ...Array.from(new Set(formatted)).sort()];
  }, [shipments]);

  const years = useMemo(() => {
    const set = new Set(
      shipments
        .map((s) =>
          s.diRegistrationDate
            ? new Date(s.diRegistrationDate).getFullYear()
            : null,
        )
        .filter((y) => y),
    );
    return ['All', ...Array.from(set).sort((a, b) => (b as number) - (a as number))];
  }, [shipments]);

  const cargos = useMemo(() => {
    const set = new Set(shipments.map((s) => s.typeOfCargo).filter(Boolean));
    return ['All', ...Array.from(set).sort()];
  }, [shipments]);

  const months = [
    { value: 'All', label: 'All' },
    { value: '1', label: 'Jan' },
    { value: '2', label: 'Feb' },
    { value: '3', label: 'Mar' },
    { value: '4', label: 'Apr' },
    { value: '5', label: 'May' },
    { value: '6', label: 'Jun' },
    { value: '7', label: 'Jul' },
    { value: '8', label: 'Aug' },
    { value: '9', label: 'Sep' },
    { value: '10', label: 'Oct' },
    { value: '11', label: 'Nov' },
    { value: '12', label: 'Dec' },
  ];

  const selectStyle = {
    padding: '0.5rem',
    borderRadius: '4px',
    border: '1px solid var(--border-soft)',
    background: 'var(--bg-card)',
    color: 'var(--text-primary)',
  };
  const groupStyle = {
    display: 'flex',
    flexDirection: 'column' as const,
    gap: '0.25rem',
  };

  return (
    <div
      className="brokerage-filters"
      style={{
        display: 'flex',
        gap: '1rem',
        padding: '1rem',
        background: 'var(--bg-card)',
        borderRadius: '8px',
        marginBottom: '1rem',
        flexWrap: 'wrap',
      }}
    >
      <div style={groupStyle}>
        <label style={{ fontSize: '0.8rem', fontWeight: 500 }}>Year</label>
        <select
          style={selectStyle}
          value={activeFilters.year}
          onChange={(e) => onFilterChange('year', e.target.value === 'All' ? 'All' : Number(e.target.value))}
        >
          {years.map((y: any) => (
            <option key={y} value={y}>
              {y}
            </option>
          ))}
        </select>
      </div>
      <div style={groupStyle}>
        <label style={{ fontSize: '0.8rem', fontWeight: 500 }}>Month</label>
        <select
          style={selectStyle}
          value={activeFilters.month}
          onChange={(e) => onFilterChange('month', e.target.value)}
        >
          {months.map((m) => (
            <option key={m.value} value={m.value}>
              {m.label}
            </option>
          ))}
        </select>
      </div>
      <div style={groupStyle}>
        <label style={{ fontSize: '0.8rem', fontWeight: 500 }}>Analyst</label>
