const KPIFilterSidebar: React.FC<{
  shipments: Shipment[];
  onFilterChange: (filterType: keyof KpiFilters, value: any) => void;
  activeFilters: KpiFilters;
  dateSourceField?: 'actualEta' | 'diRegistrationDate';
}> = ({
  shipments,
  onFilterChange,
  activeFilters,
  dateSourceField = 'actualEta',
}) => {
  const cargoTypes = useMemo(() => {
    const types = new Set(shipments.map((s) => s.typeOfCargo).filter(Boolean));
    return Array.from(types).sort();
  }, [shipments]);

  const years = useMemo(() => {
    const yearSet = new Set(
      shipments
        .map((s) => {
          const dateString =
            dateSourceField === 'diRegistrationDate'
              ? s.diRegistrationDate
              : s.actualEta;
          if (!dateString) return null;
          const date = new Date(dateString);
          return isNaN(date.getTime()) ? null : date.getFullYear();
        })
        .filter((y) => y && !isNaN(y as number)),
    );
    return Array.from(yearSet).sort((a, b) => (b as number) - (a as number));
  }, [shipments, dateSourceField]);

  const months = [
    { value: 'All', label: 'All' },
    { value: 0, label: 'Jan' },
    { value: 1, label: 'Feb' },
    { value: 2, label: 'Mar' },
    { value: 3, label: 'Apr' },
    { value: 4, label: 'May' },
    { value: 5, label: 'Jun' },
    { value: 6, label: 'Jul' },
    { value: 7, label: 'Aug' },
    { value: 8, label: 'Sep' },
    { value: 9, label: 'Oct' },
    { value: 10, label: 'Nov' },
    { value: 11, label: 'Dec' },
  ];

  const handleCargoClick = (cargoType: string) => {
    const currentSelection = activeFilters.cargo || [];
    const newSelection = currentSelection.includes(cargoType)
      ? currentSelection.filter((c) => c !== cargoType)
      : [...currentSelection, cargoType];
    onFilterChange('cargo', newSelection);
  };

  const handleClearCargo = () => {
    onFilterChange('cargo', []);
  };

  const handleYearClick = (year: number | 'All') => {
    onFilterChange('year', year);
  };

  const handleMonthClick = (month: number | 'All') => {
    onFilterChange('month', month);
  };

  return (
    <aside className="kpi-dashboard-sidebar">
      <div className="kpi-filter-box">
        <h4>Year</h4>
        <div className="cargo-filter-list">
          <button
            onClick={() => handleYearClick('All')}
            className={activeFilters.year === 'All' ? 'active' : ''}
          >
            All Years
          </button>
          {years.map((year) => (
            <button
              key={year as number}
              onClick={() => handleYearClick(year as number)}
              className={activeFilters.year === year ? 'active' : ''}
            >
              {year}
            </button>
          ))}
        </div>
      </div>
      <div className="kpi-filter-box">
        <h4>Month</h4>
        <div className="month-filter-grid">
          {months.map((m) => (
            <button
              key={m.label}
              onClick={() => handleMonthClick(m.value)}
              className={activeFilters.month === m.value ? 'active' : ''}
              style={m.value === 'All' ? { gridColumn: '1 / -1' } : {}}
            >
              {m.label}
            </button>
          ))}
        </div>
      </div>
      <div className="kpi-filter-box">
        <h4>Cargo</h4>
        <div className="cargo-filter-list">
          <button
            onClick={handleClearCargo}
            className={
              !activeFilters.cargo || activeFilters.cargo.length === 0
                ? 'active'
                : ''
            }
          >
            Clear Filters
          </button>
          {cargoTypes.map((type) => (
            <button
              key={type}
              onClick={() => handleCargoClick(type)}
              className={activeFilters.cargo?.includes(type) ? 'active' : ''}
            >
              {type}
            </button>
          ))}
        </div>
      </div>
    </aside>
  );
};

