interface LineChartPoint {
  value: number;
  shipments: Shipment[];
}

interface LineChartProps {
  title: string;
  subtitle: string;
  data: LineChartPoint[];
  labels: string[];
  goal?: number;
  color: string;
  onMaximize?: (() => void) | null;
  onPointClick?: ((title: string, shipments: Shipment[]) => void) | null;
}

const LineChart: React.FC<LineChartProps> = ({
  title,
  subtitle,
  data,
  labels,
  goal,
  color,
  onMaximize = null,
  onPointClick = null,
}) => {
  const [tooltip, setTooltip] = useState<any>(null);
  const [viewRange, setViewRange] = useState({
    start: 0,
    end: data.length > 0 ? data.length - 1 : 0,
  });
  const svgRef = useRef<SVGSVGElement | null>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setViewRange({
      start: 0,
      end: data.length > 0 ? data.length - 1 : 0,
    });
  }, [data]);

  const handleZoomIn = () => {
    setViewRange((prev) => {
      const currentRange = prev.end - prev.start;
      if (currentRange < 2) return prev;
      const center = prev.start + Math.floor(currentRange / 2);
      const newRange = Math.max(2, Math.ceil(currentRange / 1.5));
      const newStart = Math.max(0, center - Math.floor(newRange / 2));
      const newEnd = Math.min(data.length - 1, newStart + newRange - 1);
      return { start: newStart, end: newEnd };
    });
  };

  const handleZoomOut = () => {
    setViewRange((prev) => {
      const currentRange = prev.end - prev.start;
      if (currentRange >= data.length - 1) return prev;
      const center = prev.start + Math.floor(currentRange / 2);
      const newRange = Math.min(data.length, Math.floor(currentRange * 1.5) + 1);
      let newStart = Math.max(0, center - Math.floor(newRange / 2));
      let newEnd = Math.min(data.length - 1, newStart + newRange - 1);
      if (newEnd - newStart + 1 < newRange) {
        newStart = Math.max(0, newEnd - newRange + 1);
      }
      return { start: newStart, end: newEnd };
    });
  };

  const handleResetZoom = () => {
    setViewRange({
      start: 0,
      end: data.length > 0 ? data.length - 1 : 0,
    });
  };

  const visibleData = useMemo(
    () => data.slice(viewRange.start, viewRange.end + 1),
    [data, viewRange],
  );
  const visibleLabels = useMemo(
    () => labels.slice(viewRange.start, viewRange.end + 1),
    [labels, viewRange],
  );

  const { width, height, margin } = useMemo(() => {
    const container = containerRef.current;
    const w = container ? container.clientWidth : 400;
    const h = container ? container.clientHeight : 200;
    const m = { top: 20, right: 20, bottom: 30, left: 30 };
    return { width: w - m.left - m.right, height: h - m.top - m.bottom, margin: m };
  }, [containerRef.current]); // ok para ambiente simples

  const { yScale, linePath, areaPath, points } = useMemo(() => {
    if (visibleData.length === 0 || width <= 0 || height <= 0) {
      return {
        xScale: () => 0,
        yScale: (v: number) => v,
        linePath: '',
        areaPath: '',
        points: [] as any[],
      };
    }

    const yMax =
      Math.max(...visibleData.map((d) => d.value), goal || 0) * 1.1 || 10;
    const yMin = 0;

    const xScaleFn = (index: number) =>
      (index /
        (visibleData.length > 1 ? visibleData.length - 1 : 1)) *
      width;
    const yScaleFn = (value: number) =>
      height - ((value - yMin) / (yMax - yMin)) * height;

    const line = visibleData
      .map((d, i) => `${i === 0 ? 'M' : 'L'} ${xScaleFn(i)} ${yScaleFn(d.value)}`)
      .join(' ');

    const area = `${line} V ${height} H ${xScaleFn(0)} Z`;

    const pts = visibleData.map((d, i) => ({
      x: xScaleFn(i),
      y: yScaleFn(d.value),
      value: d.value,
      label: visibleLabels[i],
      shipments: d.shipments,
    }));

    return { yScale: yScaleFn, linePath: line, areaPath: area, points: pts };
  }, [visibleData, visibleLabels, width, height, goal]);

  const handleMouseMove = (e: React.MouseEvent, point: any) => {
    if (!svgRef.current) return;
    const svgRect = svgRef.current.getBoundingClientRect();
    setTooltip({
      ...point,
      x: e.clientX - svgRect.left,
      y: e.clientY - svgRect.top,
    });
  };

  const handleWrapperClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if (
      e.target instanceof HTMLElement &&
      (e.target.tagName === 'BUTTON' ||
        e.target.closest('.line-chart-point-group'))
    )
      return;
    if (onMaximize) onMaximize();
  };

  return (
    <div
      className={`chart-wrapper-full line-chart-card ${
        onMaximize ? 'clickable' : ''
      }`}
      onClick={handleWrapperClick}
      role={onMaximize ? 'button' : undefined}
      tabIndex={onMaximize ? 0 : undefined}
      onKeyDown={(e) => {
        if (onMaximize && (e.key === 'Enter' || e.key === ' ')) {
          e.preventDefault();
          onMaximize();
        }
      }}
    >
      <div className="line-chart-header">
        <div>
          <h4>{title}</h4>
          <p>{subtitle}</p>
        </div>
        <div className="chart-actions">
          <button onClick={handleZoomIn} title="Zoom In" aria-label="Zoom In">
            +
          </button>
          <button onClick={handleZoomOut} title="Zoom Out" aria-label="Zoom Out">
            -
          </button>
          <button
            onClick={handleResetZoom}
            title="Reset Zoom"
            aria-label="Reset Zoom"
          >
            ⟳
          </button>
        </div>
      </div>
      <div className="line-chart-container" ref={containerRef}>
        {width > 0 && height > 0 && (
          <svg
            ref={svgRef}
            className="line-chart-svg"
            viewBox={`0 0 ${width + margin.left + margin.right} ${
              height + margin.top + margin.bottom
            }`}
          >
            <g transform={`translate(${margin.left},${margin.top})`}>
              <g className="line-chart-grid">
                {Array.from({ length: 5 }).map((_, i) => (
                  <line
                    key={i}
                    x1="0"
                    x2={width}
                    y1={(i * height) / 4}
                    y2={(i * height) / 4}
                  />
                ))}
              </g>
              <g className="line-chart-axis">
                {Array.from({ length: 5 }).map((_, i) => {
                  const yValue =
                    (Math.max(
                      ...visibleData.map((d) => d.value),
                      goal || 0,
                    ) *
                      1.1 || 10) *
                    (1 - i / 4);
                  return (
                    <text
                      key={i}
                      x="-10"
                      y={(i * height) / 4}
                      dy="0.32em"
                      textAnchor="end"
                    >
                      {Math.round(yValue)}
                    </text>
                  );
                })}
                {points.map(
                  (p, i) =>
                    i % Math.ceil(visibleLabels.length / 10 || 1) === 0 && (
                      <text
                        key={i}
                        x={p.x}
                        y={height + 15}
                        textAnchor="middle"
                      >
                        {p.label}
                      </text>
                    ),
                )}
              </g>
              {goal && (
                <line
                  className="line-chart-goal"
                  x1="0"
                  x2={width}
                  y1={yScale(goal)}
                  y2={yScale(goal)}
                />
              )}
              <path
                className="line-chart-area"
                d={areaPath}
                style={{ fill: color, opacity: 0.1 }}
              />
              <path
                className="line-chart-line"
                d={linePath}
                style={{ stroke: color }}
              />
              {points.map((p, i) => (
                <g
                  key={i}
                  className="line-chart-point-group"
                  onClick={() =>
                    onPointClick &&
                    onPointClick(`${title} in ${p.label}`, p.shipments)
                  }
                  onMouseMove={(e) => handleMouseMove(e, p)}
                  onMouseLeave={() => setTooltip(null)}
                >
                  <circle
                    className="line-chart-point"
                    cx={p.x}
                    cy={p.y}
                    style={{ stroke: color }}
                  />
                  <text
                    className="line-chart-data-label"
                    x={p.x}
                    y={p.y - 10}
                    textAnchor="middle"
                  >
                    {p.value}
                  </text>
                </g>
              ))}
            </g>
          </svg>
        )}
        {tooltip && (
          <div
            className="line-chart-tooltip"
            style={{
              left: tooltip.x,
              top: tooltip.y,
              opacity: 1,
              pointerEvents: 'none',
            }}
          >
            <span className="tooltip-label">{tooltip.label}: </span>
            <span className="tooltip-value">{tooltip.value}</span>
          </div>
        )}
      </div>
    </div>
  );
};

interface VerticalBarChartData {
  labels: string[];
  datasets: Array<{
    label: string;
    data: number[];
    terminals?: string[];
    shipments?: Shipment[][];
  }>;
}

const VerticalBarChart: React.FC<{
  title: string;
  data: VerticalBarChartData;
  onSegmentClick?: ((title: string, shipments: Shipment[]) => void) | null;
}> = ({ title, data, onSegmentClick = null }) => {
  if (!data || !data.datasets || data.datasets.length === 0) {
    return <div className="no-data-message">No data for {title}</div>;
  }

  const { labels, datasets } = data;
  const totals = labels.map((_, i) =>
    datasets.reduce((sum, ds) => sum + (ds.data[i] || 0), 0),
  );
  const maxTotal = Math.max(...totals) * 1.1 || 10;

  const cargoVolumeLegend = useMemo(
    () =>
      Object.entries(TERMINAL_COLOR_MAP).map(([label, color]) => ({
        label,
        color,
      })),
    [],
  );

  return (
    <div className="chart-wrapper-full v-bar-chart-card">
      <h4 className="v-bar-chart-title">{title}</h4>
      <div
        className="v-bar-chart-container"
        style={{ gridTemplateColumns: `repeat(${labels.length}, 1fr)` }}
      >
        {labels.map((label, i) => (
          <div key={label} className="v-bar-group">
            <div className="v-bar-total">{totals[i]}</div>
            <div className="v-bar-stack" style={{ height: '150px' }}>
              {datasets.map((ds) => {
                const value = ds.data[i] || 0;
                if (value === 0) return null;
                const height = maxTotal > 0 ? (value / maxTotal) * 100 : 0;
                const terminal = ds.terminals ? ds.terminals[i] : ds.label;
                const shipments = ds.shipments ? ds.shipments[i] : [];

                const handleClick = () => {
                  if (onSegmentClick && shipments) {
                    onSegmentClick(`${ds.label} in ${label}`, shipments);
                  }
                };

                const terminalColor = TERMINAL_COLOR_MAP[terminal];
                return (
                  <button
                    key={ds.label + '-' + i}
                    className="v-bar-segment"
                    onClick={handleClick}
                    disabled={!onSegmentClick}
                    style={{
                      height: `${height}%`,
                      backgroundColor: terminalColor || '#6b7280',
                    }}
                    title={`${terminal}: ${value}`}
                  />
                );
              })}
            </div>
            <span className="v-bar-label">{label}</span>
          </div>
        ))}
      </div>
      {title === 'Cargo Volume' && (
        <div className="v-bar-legend">
          {cargoVolumeLegend.map((item) => (
            <div key={item.label} className="v-bar-legend-item">
              <span
                className="legend-marker"
                style={{ backgroundColor: item.color }}
              />
              <span>{item.label}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

