const CargosInTransitDashboard: React.FC<KPIPageProps> = ({
  shipments,
  onFilterChange,
  filters,
}) => {
  const [selectedShipments, setSelectedShipments] = useState<{
    title: string;
    data: Shipment[];
  } | null>(null);

  const handleChartClick = (title: string, data: Shipment[]) => {
    setSelectedShipments({ title: `Shipments for: ${title}`, data });
  };

  const filteredShipments = useMemo(
    () =>
      shipments.filter((s) => {
        const cargoMatch =
          !filters.cargo ||
          filters.cargo.length === 0 ||
          filters.cargo.includes(s.typeOfCargo || '');
        if (!s.actualEta) return false;
        const shipmentDate = new Date(s.actualEta);
        if (isNaN(shipmentDate.getTime())) return false;
        const yearMatch =
          filters.year === 'All' || shipmentDate.getFullYear() === filters.year;
        const monthMatch =
          filters.month === 'All' || shipmentDate.getMonth() === filters.month;
        return cargoMatch && yearMatch && monthMatch;
      }),
    [shipments, filters],
  );

  const shipmentsData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = {
      CIF: [],
      FOB: [],
      DAP: [],
    };
    filteredShipments.forEach((s) => {
      if (s.incoterm && groups.hasOwnProperty(s.incoterm)) {
        groups[s.incoterm].push(s);
      }
    });
    const colorMap: Record<string, string> = {
      CIF: '#8b5cf6',
      FOB: '#3b82f6',
      DAP: '#ec4899',
    };
    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const shipmentStatusData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = {
      'Doc Review': [],
      'In Transit': [],
      'At Port': [],
    };
    filteredShipments.forEach((s) => {
      if (s.status === ImportStatus.DocumentReview)
        groups['Doc Review'].push(s);
      if (s.status === ImportStatus.InProgress) groups['In Transit'].push(s);
      if (
        s.status === ImportStatus.AtPort ||
        s.status === ImportStatus.CargoReady
      )
        groups['At Port'].push(s);
    });
    const colorMap: Record<string, string> = {
      'Doc Review': '#f97316',
      'In Transit': '#3b82f6',
      'At Port': '#ef4444',
    };
    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const sapPoStatusData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = { OK: [], Pending: [] };
    filteredShipments.forEach((s) =>
      s.poSap ? groups.OK.push(s) : groups.Pending.push(s),
    );
    const colorMap: Record<string, string> = {
      OK: '#10b981',
      Pending: '#ef4444',
    };
    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const docStatusData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = {
      Approved: [],
      'Not Approved': [],
    };
    filteredShipments.forEach((s) => groups.Approved.push(s));
    const colorMap: Record<string, string> = {
      Approved: '#10b981',
      'Not Approved': '#ef4444',
    };
    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const cargoVolumeDataStack = useMemo(() => {
    const months: {
      [key: string]: { [key: string]: { volume: number; shipments: Shipment[] } };
    } = {};
    const terminals = new Set<string>();
    // Updated to full year to fix missing data for early months
    const monthLabels = [
      'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
      'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
    ];

    monthLabels.forEach((m) => (months[m] = {}));

    filteredShipments.forEach((s) => {
      if (!s.actualEta) return;
      const date = new Date(s.actualEta);
      if (isNaN(date.getTime())) return;

      const monthIndex = date.getMonth();
      // Only process valid months (0-11)
      if (monthIndex >= 0 && monthIndex < 12) {
        const monthName = monthLabels[monthIndex];
        const terminal = normalizeTerminalName(s.bondedWarehouse);
        terminals.add(terminal);

        let containerVolume = 0;
        if (s.shipmentType === 'FCL' || s.shipmentType === 'FCL/LCL') {
          containerVolume = s.fcl || 0;
        }
        if (containerVolume > 0) {
          if (!months[monthName][terminal])
            months[monthName][terminal] = { volume: 0, shipments: [] };
          months[monthName][terminal].volume += containerVolume;
          months[monthName][terminal].shipments.push(s);
        }
      }
    });

    const sortedTerminals = Array.from(terminals).sort();

    return {
      labels: monthLabels,
      datasets: sortedTerminals.map((terminal) => ({
        label: terminal,
        data: monthLabels.map((m) => months[m][terminal]?.volume || 0),
        terminals: monthLabels.map(() => terminal),
        shipments: monthLabels.map(
          (m) => months[m][terminal]?.shipments || [],
        ),
      })),
    };
  }, [filteredShipments]);

  return (
    <div className="cargos-in-transit-grid">
      <KPIFilterSidebar
        shipments={shipments}
        onFilterChange={onFilterChange}
        activeFilters={filters}
      />
      <main className="kpi-dashboard-main-grid">
        <div className="kpi-main-charts">
          <DoughnutChart
            title="Shipments"
            data={shipmentsData}
            onSegmentClick={handleChartClick}
          />
          <DoughnutChart
            title="Shipment Status"
            data={shipmentStatusData}
            onSegmentClick={handleChartClick}
          />
          <DoughnutChart
            title="SAP PO Status"
            data={sapPoStatusData}
            onSegmentClick={handleChartClick}
          />
          <DoughnutChart
            title="Document Status"
            data={docStatusData}
            onSegmentClick={handleChartClick}
          />
        </div>
        <VerticalBarChart
          title="Cargo Volume"
          data={cargoVolumeDataStack}
          onSegmentClick={handleChartClick}
        />
        {selectedShipments && (
          <ShipmentsTable
            title={selectedShipments.title}
            shipments={selectedShipments.data}
            onClose={() => setSelectedShipments(null)}
          />
        )}
      </main>
    </div>
  );
};

const PerformanceDashboard: React.FC<KPIPageProps> = ({
