  filters,
}) => {
  const [maximizedChart, setMaximizedChart] = useState<any>(null);
  const [selectedShipments, setSelectedShipments] = useState<{
    title: string;
    data: Shipment[];
  } | null>(null);

  const handleChartClick = (title: string, data: Shipment[]) => {
    setSelectedShipments({ title: `Shipments for: ${title}`, data });
  };

  const filteredShipments = useMemo(
    () =>
      shipments.filter((s) => {
        const cargoMatch =
          !filters.cargo ||
          filters.cargo.length === 0 ||
          filters.cargo.includes(s.typeOfCargo || '');
        if (!s.diRegistrationDate) return false;
        const shipmentDate = new Date(s.diRegistrationDate);
        if (isNaN(shipmentDate.getTime())) return false;
        const yearMatch =
          filters.year === 'All' || shipmentDate.getFullYear() === filters.year;
        const monthMatch =
          filters.month === 'All' || shipmentDate.getMonth() === filters.month;
        return cargoMatch && yearMatch && monthMatch;
      }),
    [shipments, filters],
  );

  const incotermData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = {
      DAP: [],
      CIF: [],
      FOB: [],
    };
    filteredShipments.forEach((s) => {
      if (s.incoterm && groups.hasOwnProperty(s.incoterm)) {
        groups[s.incoterm].push(s);
      }
    });
    const colorMap: Record<string, string> = {
      DAP: '#a855f7',
      CIF: '#3b82f6',
      FOB: '#10b981',
    };
    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const diParamData = useMemo(() => {
    const groups: {
      [key: string]: { uniqueDIs: Map<string, Shipment> };
    } = {
      Green: { uniqueDIs: new Map() },
      Yellow: { uniqueDIs: new Map() },
      Red: { uniqueDIs: new Map() },
    };

    filteredShipments.forEach((s) => {
      if (s.di && s.parametrization && groups.hasOwnProperty(s.parametrization)) {
        if (!groups[s.parametrization].uniqueDIs.has(s.di)) {
          groups[s.parametrization].uniqueDIs.set(s.di, s);
        }
      }
    });

    const colorMap: Record<string, string> = {
      Green: '#10b981',
      Yellow: '#facc15',
      Red: '#ef4444',
    };

    return Object.entries(groups).map(([label, data]) => ({
      label,
      value: data.uniqueDIs.size,
      shipments: Array.from(data.uniqueDIs.values()),
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const disPerMonth = useMemo(() => {
    const monthlyUniqueDIs = Array(12)
      .fill(null)
      .map(() => new Map<string, Shipment>());

    filteredShipments.forEach((shipment) => {
      if (shipment.di && shipment.diRegistrationDate) {
        const date = new Date(shipment.diRegistrationDate);
        if (isNaN(date.getTime())) return;
        const month = date.getMonth();
        if (month >= 0 && month < 12) {
          if (!monthlyUniqueDIs[month].has(shipment.di)) {
            monthlyUniqueDIs[month].set(shipment.di, shipment);
          }
        }
      }
    });

    const monthlyCounts = monthlyUniqueDIs.map((m) => m.size);
    const monthlyShipments = monthlyUniqueDIs.map((m) => Array.from(m.values()));
    const labels = [
      'Janeiro',
      'Fevereiro',
      'Março',
      'Abril',
      'Maio',
      'Junho',
      'Julho',
      'Agosto',
      'Setembro',
      'Outubro',
      'Novembro',
      'Dezembro',
    ];
    return {
      labels,
      datasets: [
        {
          label: 'DIs',
          data: monthlyCounts,
          shipments: monthlyShipments,
        },
      ],
    };
  }, [filteredShipments]);

  const lineChartData = useMemo(() => {
    const months = Array(12)
      .fill(null)
      .map(() => ({
        clearance: [] as number[],
        delivery: [] as number[],
        operation: [] as number[],
        nf: [] as number[],
        clearanceShipments: [] as Shipment[],
        deliveryShipments: [] as Shipment[],
        operationShipments: [] as Shipment[],
        nfShipments: [] as Shipment[],
      }));

    const shipmentsForPerf = filteredShipments.filter(
      (s) => s.uniqueDi !== 'Yes',
    );

    shipmentsForPerf.forEach((s) => {
      if (!s.diRegistrationDate) return;
      const date = new Date(s.diRegistrationDate);
      if (isNaN(date.getTime())) return;
      const month = date.getMonth();
      if (month < 0 || month > 11) return;

      const clearance = calculateDaysBetween(
        s.cargoPresenceDate,
        s.greenChannelOrDeliveryAuthorizedDate,
      );
      const delivery = calculateDaysBetween(
        s.greenChannelOrDeliveryAuthorizedDate,
        s.firstTruckDelivery,
      );
      const operation = calculateDaysBetween(s.actualEta, s.greenChannelOrDeliveryAuthorizedDate);
      const nf = calculateDaysBetween(
        s.greenChannelOrDeliveryAuthorizedDate,
        s.nfIssueDate,
      );

      if (clearance !== null) {
        months[month].clearance.push(clearance);
        months[month].clearanceShipments.push(s);
      }
      if (delivery !== null) {
        months[month].delivery.push(delivery);
        months[month].deliveryShipments.push(s);
      }
      if (operation !== null) {
        months[month].operation.push(operation);
        months[month].operationShipments.push(s);
      }
      if (nf !== null) {
        months[month].nf.push(nf);
        months[month].nfShipments.push(s);
      }
    });

    const avg = (arr: number[]) =>
      arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;

    const labels = [
      'Janeiro',
      'Fevereiro',
      'Março',
      'Abril',
      'Maio',
      'Junho',
      'Julho',
      'Agosto',
      'Setembro',
      'Outubro',
      'Novembro',
      'Dezembro',
    ];

    return {
      labels,
      clearance: months.map((m) => ({
        value: Math.round(avg(m.clearance)),
        shipments: m.clearanceShipments,
      })),
      delivery: months.map((m) => ({
        value: Math.round(avg(m.delivery)),
        shipments: m.deliveryShipments,
      })),
      operation: months.map((m) => ({
        value: Math.round(avg(m.operation)),
        shipments: m.operationShipments,
      })),
      nf: months.map((m) => ({
        value: Math.round(avg(m.nf)),
        shipments: m.nfShipments,
      })),
    };
  }, [filteredShipments]);

  const chartProps = {
    clearance: {
      title: 'Clearance Time',
      subtitle: 'Business Days - Goal: 5',
      data: lineChartData.clearance,
      labels: lineChartData.labels,
      goal: 5,
      color: '#06b6d4',
    },
    delivery: {
      title: 'Delivery Time',
      subtitle: 'Business Days - Goal: 3',
      data: lineChartData.delivery,
      labels: lineChartData.labels,
      goal: 3,
      color: '#10b981',
    },
    operation: {
      title: 'Operation Time',
      subtitle: 'Business Days - Goal: 8',
      data: lineChartData.operation,
      labels: lineChartData.labels,
      goal: 8,
      color: '#0ea5e9',
    },
    nf: {
      title: 'NF Issue Time',
      subtitle: 'Business Days - Goal: 6',
      data: lineChartData.nf,
      labels: lineChartData.labels,
      goal: 6,
      color: '#a855f7',
    },
  };

  return (
    <div className="performance-grid">
      <KPIFilterSidebar
        shipments={shipments}
        onFilterChange={onFilterChange}
        activeFilters={filters}
        dateSourceField="diRegistrationDate"
      />
      <main className="performance-main">
        <div className="performance-top-row">
          <DoughnutChart
            title="Incoterm"
            data={incotermData}
            onSegmentClick={handleChartClick}
          />
          <VerticalBarChart
            title="DIs Registers"
            data={disPerMonth}
            onSegmentClick={handleChartClick}
          />
          <DoughnutChart
            title="DI Parameterization"
            data={diParamData}
            strokeWidth={20}
            onSegmentClick={handleChartClick}
          />
        </div>
        <div className="performance-bottom-row">
          <LineChart
            {...chartProps.clearance}
            onMaximize={() => setMaximizedChart(chartProps.clearance)}
            onPointClick={handleChartClick}
          />
          <LineChart
            {...chartProps.delivery}
            onMaximize={() => setMaximizedChart(chartProps.delivery)}
            onPointClick={handleChartClick}
          />
          <LineChart
            {...chartProps.operation}
            onMaximize={() => setMaximizedChart(chartProps.operation)}
            onPointClick={handleChartClick}
          />
          <LineChart
            {...chartProps.nf}
            onMaximize={() => setMaximizedChart(chartProps.nf)}
            onPointClick={handleChartClick}
