};

const OperationStatusDashboard: React.FC<KPIPageProps> = ({
  shipments,
  onFilterChange,
  filters,
}) => {
  const [selectedShipments, setSelectedShipments] = useState<{
    title: string;
    data: Shipment[];
  } | null>(null);

  const handleChartClick = (title: string, data: Shipment[]) => {
    setSelectedShipments({ title: `Shipments for: ${title}`, data });
  };

  const filteredShipments = useMemo(
    () =>
      shipments.filter((s) => {
        const cargoMatch =
          !filters.cargo ||
          filters.cargo.length === 0 ||
          filters.cargo.includes(s.typeOfCargo || '');
        if (!s.actualEta) return false;
        const shipmentDate = new Date(s.actualEta);
        if (isNaN(shipmentDate.getTime())) return false;
        const yearMatch =
          filters.year === 'All' || shipmentDate.getFullYear() === filters.year;
        const monthMatch =
          filters.month === 'All' || shipmentDate.getMonth() === filters.month;
        return cargoMatch && yearMatch && monthMatch;
      }),
    [shipments, filters],
  );

  const statusByBLsData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = {
      'IN TRANSIT': [],
      'AT THE PORT': [],
      'DI REGISTERED': [],
      'CARGO CLEARED': [],
    };
    filteredShipments.forEach((s) => {
      if (!s.status) return;
      if (groups.hasOwnProperty(s.status)) {
        groups[s.status].push(s);
      } else if (s.status === ImportStatus.CargoReady) {
        groups['AT THE PORT'].push(s);
      }
    });

    const colorMap: Record<string, string> = {
      'IN TRANSIT': '#3b82f6',
      'AT THE PORT': '#f97316',
      'DI REGISTERED': '#facc15',
      'CARGO CLEARED': '#10b981',
    };

    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const statusByContainersData = useMemo(() => {
    const groups: {
      [key: string]: { shipments: Shipment[]; count: number };
    } = {
      'IN TRANSIT': { shipments: [], count: 0 },
      'AT THE PORT': { shipments: [], count: 0 },
      'DI REGISTERED': { shipments: [], count: 0 },
      'CARGO CLEARED': { shipments: [], count: 0 },
    };
    filteredShipments.forEach((s) => {
      const containerCount =
        s.shipmentType === 'FCL' || s.shipmentType === 'FCL/LCL'
          ? s.fcl || 1
          : 0;
      if (s.status && groups.hasOwnProperty(s.status)) {
        groups[s.status].count += containerCount;
        groups[s.status].shipments.push(s);
      } else if (s.status === ImportStatus.CargoReady) {
        groups['AT THE PORT'].count += containerCount;
        groups['AT THE PORT'].shipments.push(s);
      }
    });

    const colorMap: Record<string, string> = {
      'IN TRANSIT': '#3b82f6',
      'AT THE PORT': '#f97316',
      'DI REGISTERED': '#facc15',
      'CARGO CLEARED': '#10b981',
    };

    return Object.entries(groups).map(([label, data]) => ({
      label,
      value: Math.round(data.count),
      shipments: data.shipments,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const cargoValueByWarehouseData = useMemo(() => {
    const warehouses: {
      [key: string]: { shipments: Shipment[]; total: number };
    } = {};
    filteredShipments.forEach((s) => {
      const warehouse = normalizeTerminalName(s.bondedWarehouse);
      if (warehouse === 'N/A') return;
      if (!warehouses[warehouse]) {
        warehouses[warehouse] = { shipments: [], total: 0 };
      }
      warehouses[warehouse].total += s.invoiceValue || 0;
      warehouses[warehouse].shipments.push(s);
    });
    return Object.entries(warehouses).map(([label, data]) => ({
      label,
      value: data.total,
      shipments: data.shipments,
    }));
  }, [filteredShipments]);

  const containerVolumeByWarehouseData = useMemo(() => {
    const warehouses: {
      [key: string]: { shipments: Shipment[]; total: number };
    } = {};
    filteredShipments.forEach((s) => {
      const warehouse = normalizeTerminalName(s.bondedWarehouse);
      if (warehouse === 'N/A') return;
      if (!warehouses[warehouse]) {
        warehouses[warehouse] = { shipments: [], total: 0 };
      }
      const containerCount =
        s.shipmentType === 'FCL' || s.shipmentType === 'FCL/LCL'
          ? s.fcl || 1
          : 0;
      warehouses[warehouse].total += containerCount;
      warehouses[warehouse].shipments.push(s);
    });
    return Object.entries(warehouses).map(([label, data]) => ({
      label,
      value: data.total,
      shipments: data.shipments,
    }));
  }, [filteredShipments]);

  return (
    <div className="operation-status-grid">
      <KPIFilterSidebar
        shipments={shipments}
        onFilterChange={onFilterChange}
        activeFilters={filters}
      />
      <main className="operation-status-main">
        <div className="operation-charts-column">
          <DoughnutChart
            title="Shipment Status (by BLs)"
            data={statusByBLsData}
            onSegmentClick={handleChartClick}
          />
          <DoughnutChart
            title="Shipment Status (by Containers)"
            data={statusByContainersData}
            onSegmentClick={handleChartClick}
          />
        </div>
        <div className="operation-charts-column">
          <HorizontalBarChart
            title="Cargo Value"
            data={cargoValueByWarehouseData}
            colorMap={TERMINAL_COLOR_MAP}
            onBarClick={handleChartClick}
          />
          <HorizontalBarChart
            title="Container Volume"
            data={containerVolumeByWarehouseData}
            colorMap={TERMINAL_COLOR_MAP}
            onBarClick={handleChartClick}
          />
        </div>
        {selectedShipments && (
          <div
            className="operation-charts-column"
            style={{ gridColumn: '1 / -1' }}
          >
            <ShipmentsTable
              title={selectedShipments.title}
              shipments={selectedShipments.data}
              onClose={() => setSelectedShipments(null)}
            />
          </div>
        )}
      </main>
    </div>
  );
};

