interface UploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  onUpload: (shipments: Shipment[]) => Promise<void>;
}

const UploadModal: React.FC<UploadModalProps> = ({
  isOpen,
  onClose,
  onUpload,
}) => {
  const [file, setFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const chosen = e.target.files?.[0] || null;
    setFile(chosen);
    setError('');
    setSuccess('');
  };

  const handleUpload = () => {
    if (!file) {
      setError('Please select a file first.');
      return;
    }
    setIsUploading(true);
    setError('');
    setSuccess('');

    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = XLSX.utils.sheet_to_json(worksheet, { header: 1 });

        const headers = json[0] as string[];
        const rows = json.slice(1);

        const shipmentsToUpload = rows
          .map((rowArray, index) => {
            const row = rowArray as any[];
            const shipment: Partial<Shipment> = {
              id: `row-${index}`,
              containers: [],
              costs: [],
            };
            headers.forEach((header, i) => {
              const key = header.toLowerCase().replace(/\s+/g, '');
              const value = row[i];
              if (key.includes('bl')) shipment.blAwb = value;
              if (key.includes('description') || key.includes('cargo'))
                shipment.typeOfCargo = value;
              if (key.includes('costcenter')) shipment.costCenter = value;
              if (key.includes('status')) shipment.status = value;
              if (key.includes('eta')) shipment.actualEta = parseDateFromExcel(value);
              if (key.includes('etd')) shipment.actualEtd = parseDateFromExcel(value);
              if (key.includes('incoterm')) shipment.incoterm = value;
              if (key.includes('posap')) shipment.poSap = value;
              if (key.includes('approveddraftdi'))
                shipment.approvedDraftDi = value;
              if (key.includes('bondedwarehouse'))
                shipment.bondedWarehouse = value;
              if (key.includes('fcl'))
                shipment.fcl = typeof value === 'number' ? value : 0;
              if (key.includes('invoicevalue'))
                shipment.invoiceValue =
                  typeof value === 'number' ? value : 0;
              if (key.includes('parametrization'))
                shipment.parametrization = value;
              if (key.includes('cargopresence'))
                shipment.cargoPresenceDate = parseDateFromExcel(value);
              if (key.includes('diregistration'))
                shipment.diRegistrationDate = parseDateFromExcel(value);
              if (
                key.includes('greenchannel') ||
                key.includes('deliveryauthorized')
              )
                shipment.greenChannelOrDeliveryAuthorizedDate =
                  parseDateFromExcel(value);
              if (key.includes('firsttruck'))
                shipment.firstTruckDelivery = parseDateFromExcel(value);
              if (key.includes('lasttruck'))
                shipment.lastTruckDelivery = parseDateFromExcel(value);
              if (key.includes('nfissue'))
                shipment.nfIssueDate = parseDateFromExcel(value);
              if (
                key.includes('di') &&
                !key.includes('registration') &&
                !key.includes('draft') &&
                !key.includes('cif')
              )
                shipment.di = value;
              if (key.includes('uniquedi')) shipment.uniqueDi = value;
            });
            return shipment as Shipment;
          })
          .filter((s) => s.blAwb);

        await onUpload(shipmentsToUpload);

        setSuccess(`${shipmentsToUpload.length} shipments processed successfully!`);
        setFile(null);
      } catch (err) {
        console.error(err);
        setError('Failed to process the Excel file. Please check the format.');
      } finally {
        setIsUploading(false);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const resetState = () => {
    setFile(null);
    setIsUploading(false);
    setError('');
    setSuccess('');
  };

  const handleClose = () => {
    resetState();
    onClose();
  };

  return (
    <Modal isOpen={isOpen} onClose={handleClose}>
      <div className="modal-header">
        <h3>Upload Shipments</h3>
        <button onClick={handleClose}>
          <span className="material-symbols-outlined">close</span>
        </button>
      </div>
      <div className="modal-body">
        {error && <div className="error-banner">{error}</div>}
        {success && <div className="success-banner">{success}</div>}

        <div
          className="file-drop-area"
          onClick={() => fileInputRef.current?.click()}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => {
            e.preventDefault();
            const dropped = e.dataTransfer.files?.[0] || null;
            setFile(dropped);
          }}
        >
          <input
            type="file"
            ref={fileInputRef}
            onChange={handleFileChange}
            accept=".xlsx, .xls"
            style={{ display: 'none' }}
          />
          {file ? (
            <p>Selected file: {file.name}</p>
          ) : (
            <>
              <span className="material-symbols-outlined">cloud_upload</span>
              <p>Drag &amp; drop your Excel file here, or click to select.</p>
            </>
          )}
        </div>
      </div>
      <div className="modal-actions-footer">
        <button className="btn-secondary" onClick={handleClose}>
          Cancel
        </button>
        <button
          className="btn-primary"
          onClick={handleUpload}
          disabled={!file || isUploading}
        >
          {isUploading ? <LoadingSpinner /> : 'Upload'}
        </button>
      </div>
    </Modal>
  );
};

