const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [userData, setUserData] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarCollapsed, setSidebarCollapsed] = useState(false);

  const [activePage, setActivePage] = useState('Dashboard');
  const [pageState, setPageState] = useState<any>({});

  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [dataLoading, setDataLoading] = useState(true);
  const [dataError, setDataError] = useState('');

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(async (firebaseUser) => {
      if (firebaseUser) {
        setUser(firebaseUser);
        const userDoc = await firestore
          .collection('users')
          .doc(firebaseUser.uid)
          .get();
        if (userDoc.exists) {
          setUserData(userDoc.data() as User);
        } else {
          setUserData({
            id: firebaseUser.uid,
            name: firebaseUser.displayName || 'New User',
            username: firebaseUser.email || '',
            role: 'COMEX',
          });
        }
      } else {
        setUser(null);
        setUserData(null);
      }
      setIsLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const fetchShipments = async () => {
      if (!user) return;
      setDataLoading(true);
      setDataError('');
      try {
        const snapshot = await firestore.collection('shipments').get();
        const shipmentsData = snapshot.docs.map(
          (doc) => ({ id: doc.id, ...doc.data() } as Shipment),
        );
        setShipments(shipmentsData);
      } catch (err) {
        console.error('Error fetching shipments:', err);
        setDataError('Failed to load shipment data.');
      } finally {
        setDataLoading(false);
      }
    };
    fetchShipments();
  }, [user]);

  const handleUploadShipments = async (newShipments: Shipment[]) => {
    const batch = firestore.batch();

    newShipments.forEach((shipment) => {
      const docRef = firestore
        .collection('shipments')
        .doc(shipment.blAwb.replace(/\//g, '-'));
      batch.set(docRef, shipment, { merge: true });
    });

    await batch.commit();

    const snapshot = await firestore.collection('shipments').get();
    const shipmentsData = snapshot.docs.map(
      (doc) => ({ id: doc.id, ...doc.data() } as Shipment),
    );
    setShipments(shipmentsData);
  };

  const handleNavigate = (page: string, state: object = {}) => {
    setActivePage(page);
    setPageState(state);
  };

  if (isLoading) {
    return <LoadingSpinner />;
  }

  if (!user) {
    return <LoginPage onLoginSuccess={() => {}} />;
  }

  const renderPage = () => {
    switch (activePage) {
      case 'Dashboard':
        return (
          <DashboardPage shipments={shipments} onNavigate={handleNavigate} user={userData} />
        );
      case 'Imports':
        return (
          <ImportsPage
            shipments={shipments}
            isLoading={dataLoading}
            error={dataError}
            onUpload={handleUploadShipments}
            initialFilters={pageState}
          />
        );
      case 'KPIs':
        return <KPIsPage shipments={shipments} />;
      case 'Brokerage KPIs':
        return <BrokerageKPIsPage shipments={shipments} />;
      default:
        return <div>Page not found</div>;
    }
  };

  const navItems = [
    { name: 'Dashboard', icon: 'dashboard' },
    { name: 'Imports', icon: 'directions_boat' },
    { name: 'KPIs', icon: 'bar_chart' },
    { name: 'Brokerage KPIs', icon: 'pie_chart' },
  ];

  return (
    <div
      className={
        'app-container ' + (isSidebarCollapsed ? 'sidebar-collapsed' : '')
      }
    >
      <aside className={'sidebar ' + (isSidebarCollapsed ? 'collapsed' : '')}>
        <div>
          <header className="sidebar-header">
            <span>Navigator</span>
            {!isSidebarCollapsed && (
              <button
                className="sidebar-toggle"
                onClick={() => setSidebarCollapsed(true)}
                aria-label="Collapse sidebar"
              >
                <span className="material-symbols-outlined">menu_open</span>
              </button>
            )}
          </header>
          <nav>
            <ul className="nav-links">
              {navItems.map((item) => (
                <li key={item.name}>
                  <a
                    href="#"
                    className={
                      'nav-link ' +
                      (activePage === item.name ? 'active' : '')
                    }
                    onClick={(e) => {
                      e.preventDefault();
                      handleNavigate(item.name);
                    }}
                    title={item.name}
                  >
                    <span className="material-symbols-outlined nav-icon">
                      {item.icon}
                    </span>
                    <span className="nav-label">{item.name}</span>
                  </a>
                </li>
              ))}
            </ul>
          </nav>
        </div>
        <footer className="sidebar-footer">
          {isSidebarCollapsed ? (
            <button
              className="sidebar-toggle"
              onClick={() => setSidebarCollapsed(false)}
              aria-label="Expand sidebar"
            >
              <span className="material-symbols-outlined">menu</span>
            </button>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column' }}>
              <div className="user-info">
                <div
                  className="user-avatar"
                  style={{
                    width: '32px',
                    height: '32px',
                    borderRadius: '50%',
                    background: 'var(--accent-red)',
                    color: 'white',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '14px',
                  }}
                >
                  {userData?.name?.charAt(0).toUpperCase()}
                </div>
                <div className="user-details">
                  <span className="user-name">{userData?.name}</span>
                  <span className="user-role">{userData?.role}</span>
                </div>
              </div>
              <a
                href="#"
                className="nav-link"
                onClick={() => auth.signOut()}
                style={{ marginTop: '0.5rem' }}
              >
                <span className="material-symbols-outlined nav-icon">
                  logout
                </span>
                <span className="nav-label">Logout</span>
              </a>
            </div>
          )}
        </footer>
      </aside>
      <main className="main-content">{renderPage()}</main>
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

