  user?: User | null;
}> = ({ shipments, onNavigate, user }) => {
  const kpiData = useMemo(() => {
    const now = new Date();
    const thirtyDaysAgo = new Date(
      now.getFullYear(),
      now.getMonth(),
      now.getDate() - 30,
    );

    const recentShipments = shipments.filter(
      (s) => s.actualEta && new Date(s.actualEta) > thirtyDaysAgo,
    );
    const totalValueRecent = recentShipments.reduce(
      (sum, s) => sum + (s.invoiceValue || 0),
      0,
    );
    const onTimeShipments = shipments.filter(
      (s) =>
        s.status === ImportStatus.Delivered &&
        s.actualEta &&
        s.lastTruckDelivery &&
        new Date(s.lastTruckDelivery) <= new Date(s.actualEta),
    ).length;
    const totalDelivered = shipments.filter(
      (s) => s.status === ImportStatus.Delivered,
    ).length;
    const onTimePercentage =
      totalDelivered > 0
        ? ((onTimeShipments / totalDelivered) * 100).toFixed(0)
        : '0';
    const inTransitCount = shipments.filter(
      (s) => s.status === ImportStatus.InProgress,
    ).length;

    return {
      totalValue: totalValueRecent,
      onTime: onTimePercentage,
      inTransit: inTransitCount,
      totalShipments: shipments.length,
    };
  }, [shipments]);

  const actionItems = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const arrivingToday = shipments.filter((s) => {
      if (!s.actualEta) return false;
      return s.actualEta.split('T')[0] === todayStr;
    }).length;

    const docsPending = shipments.filter(
      (s) =>
        s.status === ImportStatus.DocumentReview ||
        (s.status === ImportStatus.DiRegistered &&
          (!s.approvedDraftDi || s.approvedDraftDi !== 'OK')),
    ).length;

    return { arrivingToday, docsPending };
  }, [shipments]);

  const shipmentStatusData = useMemo(() => {
    const statusConfig = [
      {
        label: 'Order Placed',
        statuses: [ImportStatus.OrderPlaced],
        color: '#6c757d',
      },
      {
        label: 'In Transit',
        statuses: [ImportStatus.InProgress],
        color: '#3b82f6',
      },
      {
        label: 'At Port',
        statuses: [ImportStatus.AtPort, ImportStatus.CargoReady],
        color: '#ef4444',
      },
      {
        label: 'Delivered',
        statuses: [ImportStatus.Delivered],
        color: '#10b981',
      },
    ];

    return statusConfig.map((config) => {
      const matching = shipments.filter(
        (s) => s.status && config.statuses.includes(s.status as ImportStatus),
      );
      return {
        label: config.label,
        value: matching.length,
        shipments: matching,
        color: config.color,
      };
    });
  }, [shipments]);

  const handleSegmentClick = (label: string) => {
    let statusFilter: ImportStatus | 'All' = 'All';
    if (label === 'Order Placed') statusFilter = ImportStatus.OrderPlaced;
    if (label === 'In Transit') statusFilter = ImportStatus.InProgress;
    if (label === 'At Port') statusFilter = ImportStatus.AtPort;
    if (label === 'Delivered') statusFilter = ImportStatus.Delivered;
    onNavigate('Imports', { statusFilter });
  };

  return (
    <div className="dashboard-page">
      <div className="dashboard-welcome-section">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '0.5rem' }}>
          <h1 className="dashboard-welcome-text" style={{ margin: 0 }}>Welcome back!</h1>
          {/* Weekly Report Export Button */}
          <button 
            className="btn-primary report-wk-btn" 
            onClick={() => generateWeeklyReport(shipments, user || null)}
            title="Download Weekly Report for Director"
          >
             <span className="material-symbols-outlined">description</span> Report - WK
          </button>
        </div>

        <div className="search-bar-container">
          <span className="material-symbols-outlined">search</span>
          <input
            type="text"
            className="search-input"
            placeholder="Find shipments or documents"
          />
        </div>

        <div className="quick-actions-grid">
          <button className="quick-action-card">
            <span className="material-symbols-outlined">add_box</span>
            <span className="quick-action-label">Create Entry</span>
          </button>
          <button
            className="quick-action-card"
            onClick={() => onNavigate('Imports')}
          >
            <span className="material-symbols-outlined">local_shipping</span>
            <span className="quick-action-label">Track Shipment</span>
          </button>
          <button className="quick-action-card">
            <span className="material-symbols-outlined">description</span>
            <span className="quick-action-label">View Docs</span>
          </button>
        </div>
      </div>

      <h2 className="overview-header">Overview</h2>

      <div className="kpi-grid">
        <div className="kpi-card">
          <div className="kpi-header-row">
            <span className="kpi-title">Active Imports</span>
            <span
              className="material-symbols-outlined"
              style={{ color: 'var(--kpi-green)' }}
            >
              trending_up
            </span>
          </div>
          <div className="kpi-value">{kpiData.inTransit}</div>
          <a
            href="#"
            className="kpi-link"
            onClick={(e) => {
              e.preventDefault();
              onNavigate('Imports', { statusFilter: ImportStatus.InProgress });
            }}
          >
            View all
          </a>
        </div>
        <div className="kpi-card">
          <div className="kpi-header-row">
            <span className="kpi-title">Customs Pending</span>
            <span
              className="material-symbols-outlined"
              style={{ color: 'var(--kpi-yellow)' }}
            >
              hourglass_top
            </span>
          </div>
          <div className="kpi-value">{actionItems.docsPending}</div>
          <span className="kpi-link">Requires attention</span>
        </div>
        <div className="kpi-card">
          <div className="kpi-header-row">
            <span className="kpi-title">Arriving Today</span>
            <span
              className="material-symbols-outlined"
              style={{ color: 'var(--kpi-blue)' }}
            >
              event_available
            </span>
          </div>
          <div className="kpi-value">{actionItems.arrivingToday}</div>
          <span className="kpi-link">Check schedule</span>
        </div>
        <div className="kpi-card">
          <div className="kpi-header-row">
            <span className="kpi-title">Total Value (30d)</span>
            <span
              className="material-symbols-outlined"
              style={{ color: 'var(--accent-red)' }}
            >
              payments
            </span>
          </div>
          <div className="kpi-value" style={{ fontSize: '1.8rem' }}>
            {kpiData.totalValue.toLocaleString('en-US', {
              style: 'currency',
              currency: 'USD',
              maximumFractionDigits: 0,
            })}
          </div>
        </div>
      </div>

      <div className="dashboard-grid">
        <div className="dashboard-card chart-card">
          <h3 className="card-title">Shipment Status</h3>
          <DoughnutChart
            title=""
            data={shipmentStatusData}
            onSegmentClick={handleSegmentClick}
            size={220}
            strokeWidth={25}
          />
        </div>
      </div>
    </div>
  );
};

