const BrokerageKPIsPage: React.FC<{ shipments: Shipment[] }> = ({
  shipments,
}) => {
  const [filters, setFilters] = useState({
    analyst: 'All',
    month: 'All',
    year: new Date().getFullYear() as number | 'All',
    cargo: 'All',
  });
  const [selectedShipments, setSelectedShipments] = useState<{
    title: string;
    data: Shipment[];
  } | null>(null);

  const handleChartClick = (title: string, data: Shipment[]) => {
    setSelectedShipments({ title: `Shipments for: ${title}`, data });
  };

  const handleFilterChange = (filterName: string, value: any) => {
    setFilters((prev) => ({ ...prev, [filterName]: value }));
  };

  const filteredShipments = useMemo(() => {
    const toTitleCase = (str: string | undefined): string => {
      if (!str) return '';
      return str.replace(
        /\w\S*/g,
        (txt) => txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase(),
      );
    };

    return shipments.filter((s) => {
      const shipDate = s.diRegistrationDate
        ? new Date(s.diRegistrationDate)
        : null;
      if (!shipDate || isNaN(shipDate.getTime())) return false;
      const yearMatch =
        filters.year === 'All' ||
        shipDate.getFullYear() === filters.year;
      const monthMatch =
        filters.month === 'All' ||
        (shipDate.getMonth() + 1).toString() === filters.month;
      const analystMatch =
        filters.analyst === 'All' ||
        toTitleCase(s.technicianResponsibleBrazil) === filters.analyst;
      const cargoMatch =
        filters.cargo === 'All' || s.typeOfCargo === filters.cargo;
      return yearMatch && monthMatch && analystMatch && cargoMatch;
    });
  }, [shipments, filters]);

  const kpiMetrics = useMemo(() => {
    const totalDIs = new Set(
      filteredShipments.map((s) => s.di).filter(Boolean),
    ).size;
    const totalValue = filteredShipments.reduce(
      (sum, s) => sum + (s.invoiceValue || 0),
      0,
    );

    const clearanceTimes = filteredShipments
      .map((s) =>
        calculateDaysBetween(
          s.cargoPresenceDate,
          s.greenChannelOrDeliveryAuthorizedDate,
        ),
      )
      .filter((days): days is number => days !== null);

    const totalClearanceTime = clearanceTimes.reduce(
      (sum, days) => sum + days,
      0,
    );
    const avgClearance =
      clearanceTimes.length > 0
        ? totalClearanceTime / clearanceTimes.length
        : 0;

    const analystCount = new Set(
      filteredShipments.map((s) => s.technicianResponsibleBrazil).filter(Boolean),
    ).size;
    const dIsPerAnalyst = analystCount > 0 ? totalDIs / analystCount : totalDIs;

    return {
      totalDIs,
      totalValue,
      avgClearance: avgClearance.toFixed(1),
      dIsPerAnalyst,
    };
  }, [filteredShipments]);

  const volumeByTransport = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = {};
    filteredShipments.forEach((s) => {
      const type = s.shipmentType || 'Unknown';
      if (!groups[type]) groups[type] = [];
      groups[type].push(s);
    });

    // força existência das chaves principais
    ['FCL', 'LCL', 'FCL/LCL', 'AIR', 'RO-RO', 'GP', 'Unknown'].forEach(
      (k) => (groups[k] = groups[k] || []),
    );

    return Object.entries(groups).map(([label, list]) => ({
      label,
      value: list.length,
      shipments: list,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  const avgTimeByIncoterm = useMemo(() => {
    const groups: {
      [key: string]: { total: number; count: number; shipments: Shipment[] };
    } = {};
    filteredShipments.forEach((s) => {
      if (!s.incoterm) return;
      const days = calculateDaysBetween(s.actualEtd, s.actualEta);
      if (days === null) return;
      if (!groups[s.incoterm]) {
        groups[s.incoterm] = { total: 0, count: 0, shipments: [] };
      }
      groups[s.incoterm].total += days;
      groups[s.incoterm].count++;
      groups[s.incoterm].shipments.push(s);
    });

    ['FOB', 'CIF', 'DAP', 'FCA', 'EXW'].forEach((k) => {
      groups[k] = groups[k] || { total: 0, count: 0, shipments: [] };
    });

    return Object.entries(groups).map(([label, data]) => ({
      label,
      value: data.count > 0 ? Math.round(data.total / data.count) : 0,
      shipments: data.shipments,
    }));
  }, [filteredShipments]);

  const diChannelData = useMemo(() => {
    const groups: {
      [key: string]: { shipments: Shipment[]; uniqueDIs: Set<string> };
    } = {
      Green: { shipments: [], uniqueDIs: new Set() },
      Yellow: { shipments: [], uniqueDIs: new Set() },
      Red: { shipments: [], uniqueDIs: new Set() },
    };

    filteredShipments.forEach((s) => {
      if (s.parametrization && groups.hasOwnProperty(s.parametrization)) {
        const group = groups[s.parametrization];
        group.shipments.push(s);
        if (s.di) group.uniqueDIs.add(s.di);
      }
    });

    const colorMap: Record<string, string> = {
      Green: '#28a745',
      Yellow: '#ffc107',
      Red: '#dc3545',
    };

    return Object.entries(groups).map(([label, data]) => ({
      label,
      value: data.shipments.length,
      secondaryValue: data.uniqueDIs.size,
      shipments: data.shipments,
      color: colorMap[label],
    }));
  }, [filteredShipments]);

  return (
    <div className="brokerage-kpi-page">
      <div className="kpi-content">
        <header className="kpi-page-header">
          <h1>Brokerage KPIs</h1>
          <h2>Performance metrics for brokerage operations</h2>
        </header>

        <BrokerageKPIFilter
          shipments={shipments}
          activeFilters={filters}
          onFilterChange={handleFilterChange}
        />

        <div className="brokerage-dashboard-layout">
          <section className="brokerage-metrics-row">
            <KPIMetricCard
              icon={<span className="material-symbols-outlined">receipt_long</span>}
              title="Total DIs Registered"
              value={kpiMetrics.totalDIs}
            />
            <KPIMetricCard
              icon={<span className="material-symbols-outlined">group</span>}
              title="DIs per Analyst"
              value={kpiMetrics.dIsPerAnalyst.toFixed(1)}
            />
            <KPIMetricCard
              icon={
                <span className="material-symbols-outlined">event_available</span>
              }
              title="Avg. Clearance Time"
              value={`${kpiMetrics.avgClearance} days`}
            />
          </section>

          <section className="brokerage-charts-grid">
            <div className="chart-wrapper-full">
              <HorizontalBarChart
                title="Volume by Transport Modal"
                data={volumeByTransport}
                onBarClick={handleChartClick}
                colorMap={{
                  FCL: '#007bff',
                  LCL: '#28a745',
                  'FCL/LCL': '#6f42c1',
                  Unknown: '#6db7ff',
                  AIR: '#17a2b8',
                  'RO-RO': '#fd7e14',
                  GP: '#adb5bd',
                }}
              />
            </div>
            <div className="chart-wrapper-full">
              <HorizontalBarChart
                title="Avg. Transit Time by Incoterm"
                data={avgTimeByIncoterm}
                onBarClick={handleChartClick}
                colorMap={{
                  FOB: '#007bff',
                  CIF: '#28a745',
                  DAP: '#ffc107',
                  FCA: '#6db7ff',
                  EXW: '#dc3545',
                }}
              />
            </div>
            <div className="chart-wrapper-full">
              <DoughnutChart
                title="DI Channel Parameterization"
                data={diChannelData}
                onSegmentClick={handleChartClick}
                strokeWidth={15}
                size={150}
              />
            </div>
          </section>
        </div>

        {selectedShipments && (
          <ShipmentsTable
            title={selectedShipments.title}
            shipments={selectedShipments.data}
            onClose={() => setSelectedShipments(null)}
          />
        )}
      </div>
    </div>
  );
};

