    return Array.from(types).sort();
  }, [shipments]);

  const years = useMemo(() => {
    const yearSet = new Set(shipments.map((s) => {
      const dateString = dateSourceField === 'diRegistrationDate' ? s.diRegistrationDate : s.actualEta;
