                  <td>{s.typeOfCargo}</td>
                  <td>{formatDate(s.actualEta)}</td>
                  <td>{(s.invoiceValue || 0).toLocaleString('en-US', { style: 'currency', currency: s.invoiceCurrency || 'USD' })}</td>
