      { id: '6', di: 'DI-006', broker: 'Kuehne+Nagel', parametrization: 'Gray', transportModal: 'LCL', incoterm: 'CIF', diRegistrationDate: '2025-12-08', clearanceTime: 4, analyst: 'Maria' },
      { id: '7', di: 'DI-007', broker: 'DSV', parametrization: 'Green', transportModal: 'AIR', incoterm: 'EXW', diRegistrationDate: '2025-12-10', clearanceTime: 0.8, analyst: 'Luiz' },
      { id: '8', di: 'DI-008', broker: 'DHL', parametrization: 'Green', transportModal: 'FCL', incoterm: 'FOB', diRegistrationDate: '2025-12-12', clearanceTime: 1.1, analyst: 'Maria' },
