  }, [shipments, filters]);

  // Derived Data: DI Index
  const diIndex: DIEntry[] = useMemo(() => {
    const groups: Record<string, { channel: DIChannel; shipments: Shipment[] }> = {};
    filteredShipments.forEach(s => {
      if (s.di) {
        if (!groups[s.di]) {
          groups[s.di] = { channel: (s.parametrization as DIChannel) || 'Other', shipments: [] };
        }
        groups[s.di].shipments.push(s);
      }
    });
