    return {
      totalDIs,
      dIsPerAnalyst: totalDIs / analysts,
      avgClearance
    };
  }, [diIndex, filteredShipments]);

  // Derived Data: Volume by Transport
  const volumeByTransport = useMemo(() => {
    const counts: Record<string, { label: string, value: number, shipments: Shipment[] }> = {};
    filteredShipments.forEach(s => {
      const mode = s.transportModal || 'Unknown';
