  }, [diIndex]);

  // ✅ NEW: Share by Broker (DIs count)
  const brokerShareData = useMemo(() => {
    const groups: { [key: string]: { count: number; shipments: Shipment[] } } = {};

    diIndex.forEach((entry) => {
      // Use the broker from the first shipment of the DI
      const brokerName = entry.shipments[0]?.broker?.trim() || 'N/A';
      if (!groups[brokerName]) {
        groups[brokerName] = { count: 0, shipments: [] };
      }
      groups[brokerName].count++;
      groups[brokerName].shipments.push(...entry.shipments);
    });

    // Sort by count desc
    const sorted = Object.entries(groups).sort((a, b) => b[1].count - a[1].count);

    // Palette for brokers
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

    return sorted.map(([label, data], idx) => ({
      label,
      value: data.count,
      shipments: data.shipments,
      color: colors[idx % colors.length]
    }));
  }, [diIndex]);

  return (
    <div style={{ background: '#000000', color: '#e5e7eb', minHeight: '100vh', padding: '1.5rem', fontFamily: "'Inter', sans-serif" }}>
      <div className="kpi-content" style={{ maxWidth: '1400px', margin: '0 auto' }}>
        <header className="kpi-page-header" style={{ marginBottom: '2rem' }}>
          <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'white', margin: 0 }}>Brokerage KPIs</h1>
          <h2 style={{ fontSize: '0.875rem', color: '#9ca3af', margin: '0.25rem 0 0 0', fontWeight: 'normal' }}>Performance metrics for brokerage operations</h2>
        </header>

        <BrokerageKPIFilter activeFilters={filters} onFilterChange={handleFilterChange} />

        <div className="brokerage-dashboard-layout" style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <section className="brokerage-metrics-row" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '1rem' }}>
            <KPIMetricCard icon={<span className="material-symbols-outlined">receipt_long</span>} title="Total DIs Registered" value={kpiMetrics.totalDIs} />
            <KPIMetricCard icon={<span className="material-symbols-outlined">group</span>} title="DIs per Analyst" value={kpiMetrics.dIsPerAnalyst.toFixed(1)} />
            <KPIMetricCard icon={<span className="material-symbols-outlined">event_available</span>} title="Avg. Clearance Time" value={`${kpiMetrics.avgClearance} days`} />
          </section>

          <section className="brokerage-charts-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '0.75rem' }}>
            <div className="chart-wrapper-full"><HorizontalBarChart title="Volume by Transport Modal" data={volumeByTransport} onBarClick={handleChartClick} colorMap={{ FCL: '#007bff', LCL: '#28a745', 'FCL/LCL': '#6f42c1', Unknown: '#6db7ff', AIR: '#17a2b8', 'RO-RO': '#fd7e14', GP: '#adb5bd' }} /></div>
            <div className="chart-wrapper-full"><HorizontalBarChart title="Volume by Incoterm" data={avgTimeByIncoterm} onBarClick={handleChartClick} colorMap={{ FOB: '#007bff', CIF: '#28a745', DAP: '#ffc107', FCA: '#6db7ff', EXW: '#dc3545' }} /></div>
            <div className="chart-wrapper-full"><DoughnutChart title="Share by Broker" data={brokerShareData} onSegmentClick={handleChartClick} /></div>
            <div className="chart-wrapper-full"><DoughnutChart title="DI Channel Parameterization" data={diChannelData} onSegmentClick={handleChartClick} /></div>
          </section>
        </div>

        {selectedShipments && <ShipmentsTable title={selectedShipments.title} shipments={selectedShipments.data} onClose={() => setSelectedShipments(null)} />}
      </div>
    </div>
  );
};

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<BrokerageKPIs />);
}

export default BrokerageKPIs;

