import React, { useMemo, useState, useEffect, useRef } from 'react';
import { createRoot } from 'react-dom/client';
import Chart from 'chart.js/auto';

// --- Types ---
export type DIChannel = 'Green' | 'Yellow' | 'Red' | 'Gray' | 'Pending' | 'Other';

export interface Shipment {
  id: string;
  di?: string;
  broker?: string;
  parametrization?: string;
  transportModal?: string;
  incoterm?: string;
  diRegistrationDate?: string; // YYYY-MM-DD
  clearanceTime?: number; // days
  analyst?: string;
  [key: string]: any;
}

interface DIEntry {
  channel: DIChannel;
  shipments: Shipment[];
}

// --- Helpers ---

// --- BROKER ALLOCATION (UNIQUE DI) ------------------------------------------

const normalizeBrokerName = (raw?: string): string => {
  const v = (raw || '').toString().trim();
  return v ? v : 'Unassigned';
};

// If the same DI appears in multiple rows with different brokers,
// we mark as "Multiple" (conservative).
const pickBestBroker = (a: string, b: string) => {
  const A = normalizeBrokerName(a);
  const B = normalizeBrokerName(b);
  if (A === 'Unassigned') return B;
  if (B === 'Unassigned') return A;
  if (A === B) return A;
  return 'Multiple';
};

const buildUniqueDIBrokerIndex = (shipments: Shipment[]) => {
  const map = new Map<string, { di: string; broker: string; shipments: Shipment[] }>();

  shipments.forEach((s) => {
    const diRaw = (s.di || '').toString().trim();
    if (!diRaw) return;

    const broker = normalizeBrokerName(s.broker);

    const existing = map.get(diRaw);
    if (!existing) {
      map.set(diRaw, { di: diRaw, broker, shipments: [s] });
      return;
    }

    existing.shipments.push(s);
    existing.broker = pickBestBroker(existing.broker, broker);
  });

  return map;
};


// --- Inline Components ---

const KPIMetricCard = ({ icon, title, value }: { icon: React.ReactNode, title: string, value: string | number }) => (
  <div style={{ background: '#111827', padding: '1.5rem', borderRadius: '0.75rem', display: 'flex', alignItems: 'center', gap: '1rem', color: 'white', border: '1px solid #374151' }}>
    <div style={{ padding: '0.75rem', background: 'rgba(59, 130, 246, 0.1)', borderRadius: '0.5rem', color: '#60a5fa', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      {icon}
    </div>
    <div>
      <div style={{ fontSize: '0.875rem', color: '#9ca3af', marginBottom: '0.25rem' }}>{title}</div>
      <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#f3f4f6' }}>{value}</div>
    </div>
  </div>
);

const BrokerageKPIFilter = ({ activeFilters, onFilterChange }: any) => {
  const filters = ['Year', 'Month', 'Analyst', 'Cargo'];
  return (
    <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem', flexWrap: 'wrap' }}>
      {filters.map(label => (
        <div key={label} style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
          <label style={{ fontSize: '0.75rem', color: '#9ca3af', fontWeight: '500' }}>{label}</label>
          <select 
            style={{ background: '#000000', border: '1px solid #374151', color: 'white', padding: '0.5rem', borderRadius: '0.375rem', minWidth: '120px', fontSize: '0.875rem' }}
            value={activeFilters[label.toLowerCase()] || 'All'}
            onChange={(e) => onFilterChange({...activeFilters, [label.toLowerCase()]: e.target.value})}
          >
            <option value="All">All</option>
            {label === 'Year' && <option value="2025">2025</option>}
            {label === 'Month' && <option value="Dec">Dec</option>}
          </select>
        </div>
      ))}
    </div>
  );
};

const HorizontalBarChart = ({ title, data, onBarClick, colorMap }: any) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<Chart | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;
    if (chartRef.current) chartRef.current.destroy();

    chartRef.current = new Chart(canvasRef.current, {
      type: 'bar',
      data: {
        labels: data.map((d: any) => d.label),
        datasets: [{
          label: 'Count',
          data: data.map((d: any) => d.value),
          backgroundColor: data.map((d: any) => colorMap?.[d.label?.split(' (')[0]] || '#3b82f6'),
          borderRadius: 4,
          barThickness: 20,
        }]
      },
      options: {
        indexAxis: 'y',
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          title: { display: true, text: title, color: '#e5e7eb', align: 'start', font: { size: 14 } }
        },
        scales: {
          x: { grid: { color: '#374151' }, ticks: { color: '#9ca3af' } },
          y: { grid: { display: false }, ticks: { color: '#e5e7eb' } }
        },
        onClick: (evt, elements) => {
          if (elements.length > 0) {
            const index = elements[0].index;
            onBarClick(data[index]);
          }
        }
      }
    });
    return () => chartRef.current?.destroy();
  }, [data, title, colorMap]);

  return (
    <div style={{ background: '#111827', padding: '1rem', borderRadius: '0.75rem', border: '1px solid #374151', height: '100%', minHeight: '250px' }}>
      <canvas ref={canvasRef} />
    </div>
  );
};

const DoughnutChart = ({ title, data, onSegmentClick }: any) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const chartRef = useRef<Chart | null>(null);

  useEffect(() => {
    if (!canvasRef.current) return;
    if (chartRef.current) chartRef.current.destroy();

    const total = data.reduce((acc: number, cur: any) => acc + cur.value, 0);

    chartRef.current = new Chart(canvasRef.current, {
      type: 'doughnut',
      data: {
        labels: data.map((d: any) => d.label),
        datasets: [{
          data: data.map((d: any) => d.value),
          backgroundColor: data.map((d: any) => d.color),
          borderWidth: 0,
          hoverOffset: 4
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        cutout: '70%',
        plugins: {
          legend: { 
            position: 'right', 
            labels: { color: '#e5e7eb', usePointStyle: true, boxWidth: 8 } 
          },
          title: { display: true, text: title, color: '#e5e7eb', align: 'start', font: { size: 14 } }
        },
        onClick: (evt, elements) => {
          if (elements.length > 0) {
            const index = elements[0].index;
            onSegmentClick(data[index]);
          }
        }
      },
      plugins: [{
        id: 'centerText',
        beforeDraw: (chart) => {
          const { ctx, width, height } = chart;
          ctx.save();
          const fontSize = (height / 114).toFixed(2);
          ctx.font = `bold ${fontSize}em sans-serif`;
          ctx.textBaseline = 'middle';
          ctx.fillStyle = '#ffffff';
          const text = total.toString();

          // Calculate text position
          const textWidth = ctx.measureText(text).width;
          const legendWidth = chart.legend?.width || 0;

          // Adjust center calculation based on layout (legend is on the right)
          // We want the text centered in the doughnut chart area, not the full canvas width
          const chartAreaWidth = width - legendWidth;
          const textX = (chartAreaWidth / 2) - (textWidth / 2);
          const textY = height / 2;

          ctx.fillText(text, textX, textY);
          ctx.restore();
        }
      }]
    });
    return () => chartRef.current?.destroy();
  }, [data, title]);

  return (
    <div style={{ background: '#111827', padding: '1rem', borderRadius: '0.75rem', border: '1px solid #374151', height: '100%', minHeight: '250px' }}>
      <canvas ref={canvasRef} />
    </div>
  );
};

