      ? (filteredShipments.reduce((acc, s) => acc + (s.clearanceTime || 0), 0) / filteredShipments.length).toFixed(1) 
      : 0;

    return {
      totalDIs,
      dIsPerAnalyst: totalDIs / analysts,
      avgClearance
    };
  }, [diIndex, filteredShipments]);

  // Derived Data: Volume by Transport
  const volumeByTransport = useMemo(() => {
    const counts: Record<string, { label: string, value: number, shipments: Shipment[] }> = {};
    filteredShipments.forEach(s => {
      // 🔒 SAFE: Convert object to string if transportModal is a reference/object
      const mode = String(s.transportModal || 'Unknown');
      if (!counts[mode]) counts[mode] = { label: mode, value: 0, shipments: [] };
      counts[mode].value++;
      counts[mode].shipments.push(s);
    });
    return Object.values(counts);
  }, [filteredShipments]);

  // Derived Data: Incoterm
  const avgTimeByIncoterm = useMemo(() => {
    const counts: Record<string, { label: string, value: number, shipments: Shipment[] }> = {};
    filteredShipments.forEach(s => {
      // 🔒 SAFE: Convert object to string if incoterm is a reference/object
      const term = String(s.incoterm || 'Unknown');
      if (!counts[term]) counts[term] = { label: term, value: 0, shipments: [] };
      counts[term].value++; // Just counting volume for now as placeholder for avg time
      counts[term].shipments.push(s);
    });
    return Object.values(counts);
  }, [filteredShipments]);

  // ✅ FIX: DI Channel Parameterization aligned to DI Registration Date filters and counted by UNIQUE DI
  const diChannelData = useMemo(() => {
