      const brokerName = normalizeBrokerName(entry.shipments[0]?.broker);
      if (!groups[brokerName]) {
        groups[brokerName] = { count: 0, shipments: [] };
      }
      groups[brokerName].count++;
      groups[brokerName].shipments.push(...entry.shipments);
    });

    // Sort by count desc
    const sorted = Object.entries(groups).sort((a, b) => b[1].count - a[1].count);

    // Palette for brokers
    const colors = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1', '#14b8a6'];

    return sorted.map(([label, data], idx) => ({
      label,
      value: data.count,
      shipments: data.shipments,
      color: colors[idx % colors.length]
    }));
