      Yellow: { diCount: 0, shipments: [], color: '#F59E0B' },
      Red: { diCount: 0, shipments: [], color: '#DC2626' },
      Gray: { diCount: 0, shipments: [], color: '#94A3B8' },
      Pending: { diCount: 0, shipments: [], color: '#2563EB' },
      Other: { diCount: 0, shipments: [], color: '#7C3AED' },
    };
    diIndex.forEach((entry) => {
      const ch = entry.channel;
      groups[ch].diCount += 1;
      groups[ch].shipments.push(...entry.shipments);
    });
    const ordered: DIChannel[] = ['Green', 'Yellow', 'Red', 'Gray', 'Pending', 'Other'];
    return ordered.map((label) => ({ label, value: groups[label].diCount, shipments: groups[label].shipments, color: groups[label].color }));
  }, [filteredShipments]);

  const lineChartData = useMemo(() => {
    const months = Array(12).fill(null).map(() => ({ clearance: [] as number[], delivery: [] as number[], operation: [] as number[], nf: [] as number[], diToClearance: [] as number[], clearanceShipments: [] as Shipment[], deliveryShipments: [] as Shipment[], operationShipments: [] as Shipment[], nfShipments: [] as Shipment[], diToClearanceShipments: [] as Shipment[] }));
    filteredShipments.forEach((s) => {
      if (!s.diRegistrationDate) return;
      const date = new Date(s.diRegistrationDate);
      if (isNaN(date.getTime())) return;
      const m = date.getMonth();
      const clearance = calculateDaysBetween(s.cargoPresenceDate, s.greenChannelOrDeliveryAuthorizedDate);
      const delivery = calculateDaysBetween(s.greenChannelOrDeliveryAuthorizedDate, s.firstTruckDelivery);
      const operation = calculateDaysBetween(s.actualEta, s.greenChannelOrDeliveryAuthorizedDate);
      const nf = calculateDaysBetween(s.greenChannelOrDeliveryAuthorizedDate, s.nfIssueDate);
      const diToClearance = calculateDaysBetween(s.diRegistrationDate, s.greenChannelOrDeliveryAuthorizedDate);
      if (clearance !== null) { months[m].clearance.push(clearance); months[m].clearanceShipments.push(s); }
      if (delivery !== null) { months[m].delivery.push(delivery); months[m].deliveryShipments.push(s); }
      if (operation !== null) { months[m].operation.push(operation); months[m].operationShipments.push(s); }
      if (nf !== null) { months[m].nf.push(nf); months[m].nfShipments.push(s); }
      if (diToClearance !== null) { months[m].diToClearance.push(diToClearance); months[m].diToClearanceShipments.push(s); }
    });
    const avg = (arr: number[]) => arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;
    const labels = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    return { labels, clearance: months.map((m) => ({ value: Math.round(avg(m.clearance)), shipments: m.clearanceShipments })), delivery: months.map((m) => ({ value: Math.round(avg(m.delivery)), shipments: m.deliveryShipments })), operation: months.map((m) => ({ value: Math.round(avg(m.operation)), shipments: m.operationShipments })), nf: months.map((m) => ({ value: Math.round(avg(m.nf)), shipments: m.nfShipments })), diToClearance: months.map((m) => ({ value: Math.round(avg(m.diToClearance)), shipments: m.diToClearanceShipments })), };
  }, [filteredShipments]);

  const chartProps = {
    clearance: { title: 'Clearance Time', subtitle: 'Business Days - Goal: 5', data: lineChartData.clearance, labels: lineChartData.labels, goal: 5, color: '#0891B2' },
    delivery: { title: 'Delivery Time', subtitle: 'Business Days - Goal: 3', data: lineChartData.delivery, labels: lineChartData.labels, goal: 3, color: '#16A34A' },
    operation: { title: 'Operation Time', subtitle: 'Business Days - Goal: 8', data: lineChartData.operation, labels: lineChartData.labels, goal: 8, color: '#2563EB' },
    nf: { title: 'NF Issue Time', subtitle: 'Business Days - Goal: 6', data: lineChartData.nf, labels: lineChartData.labels, goal: 6, color: '#7C3AED' },
    diToClearance: { title: 'DI to Clearance', subtitle: 'Business Days - Goal: 2', data: lineChartData.diToClearance, labels: lineChartData.labels, goal: 2, color: '#F59E0B' },
  };

  return (
    <div className="performance-grid">
      <KPIFilterSidebar shipments={shipments} onFilterChange={onFilterChange} activeFilters={filters} dateSourceField="diRegistrationDate" />
      <main className="performance-main">
        <div className="performance-top-row" style={{ display: 'grid', gridTemplateColumns: '1.2fr 1fr 1fr', gap: '1rem' }}>
          <DoughnutChart title="Incoterms" data={incotermData} size={150} />
          <VerticalBarChart title="Monthly DIs" data={{ labels: lineChartData.labels, datasets: [{ label: 'DIs', data: Array(12).fill(0).map((_, i) => filteredShipments.filter(s => s.diRegistrationDate && new Date(s.diRegistrationDate).getMonth() === i).length) }] }} />
          <DoughnutChart title="Parametrization" data={diParamData} size={150} />
        </div>
        <div className="performance-bottom-row" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1rem' }}>
          <LineChart {...chartProps.clearance} onPointClick={handleChartClick} />
          <LineChart {...chartProps.diToClearance} onPointClick={handleChartClick} />
          <LineChart {...chartProps.delivery} onPointClick={handleChartClick} />
          <LineChart {...chartProps.operation} onPointClick={handleChartClick} />
          <LineChart {...chartProps.nf} onPointClick={handleChartClick} />
        </div>
      </main>
    </div>
  );
};

const OperationStatusDashboard: React.FC<KPIPageProps> = ({ shipments, onFilterChange, filters }) => {
  const [selectedShipments, setSelectedShipments] = useState<{ title: string; data: Shipment[]; } | null>(null);
  const handleChartClick = (title: string, data: Shipment[]) => { setSelectedShipments({ title: `Shipments for: ${title}`, data }); };

  const filteredShipments = useMemo(() => shipments.filter((s) => {
    const cargoMatch = !filters.cargo || filters.cargo.length === 0 || filters.cargo.includes(s.typeOfCargo || '');
    if (!s.actualEta) return false;
    const shipmentDate = new Date(s.actualEta);
    if (isNaN(shipmentDate.getTime())) return false;
    const yearMatch = filters.year === 'All' || shipmentDate.getFullYear() === filters.year;
    const monthMatch = filters.month === 'All' || shipmentDate.getMonth() === filters.month;
    return cargoMatch && yearMatch && monthMatch;
  }), [shipments, filters]);

  const statusByBLsData = useMemo(() => {
    const groups: { [key: string]: Shipment[] } = { 'IN TRANSIT': [], 'AT THE PORT': [], 'DI REGISTERED': [], 'CARGO CLEARED': [] };
    filteredShipments.forEach((s) => { if (s.status && groups.hasOwnProperty(s.status)) { groups[s.status].push(s); } });
    const colorMap: Record<string, string> = { 'IN TRANSIT': '#2563EB', 'AT THE PORT': '#F59E0B', 'DI REGISTERED': '#DC2626', 'CARGO CLEARED': '#16A34A' };
    return Object.entries(groups).map(([label, list]) => ({ label, value: list.length, shipments: list, color: colorMap[label] }));
  }, [filteredShipments]);

  const cargoValueByWarehouseData = useMemo(() => {
    const warehouses: { [key: string]: { shipments: Shipment[]; total: number }; } = {};
    filteredShipments.forEach((s) => {
      const warehouse = normalizeTerminalName(s.bondedWarehouse);
      if (warehouse === 'N/A') return;
      if (!warehouses[warehouse]) { warehouses[warehouse] = { shipments: [], total: 0 }; }
      warehouses[warehouse].total += s.invoiceValue || 0;
      warehouses[warehouse].shipments.push(s);
    });
    return Object.entries(warehouses).map(([label, data]) => ({ label, value: data.total, shipments: data.shipments }));
  }, [filteredShipments]);

  return (
    <div className="operation-status-grid">
      <KPIFilterSidebar shipments={shipments} onFilterChange={onFilterChange} activeFilters={filters} />
      <main className="operation-status-main" style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
        <div className="operation-charts-column" style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <DoughnutChart title="Status by BL" data={statusByBLsData} size={200} />
          <HorizontalBarChart title="Value per Terminal" data={cargoValueByWarehouseData} colorMap={TERMINAL_COLOR_MAP} onBarClick={handleChartClick} />
        </div>
        <div className="operation-charts-column" style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
           <HorizontalBarChart title="Volume per Terminal" data={cargoValueByWarehouseData} colorMap={TERMINAL_COLOR_MAP} onBarClick={handleChartClick} />
           {selectedShipments && <ShipmentsTable title={selectedShipments.title} shipments={selectedShipments.data} onClose={() => setSelectedShipments(null)} />}
        </div>
      </main>
    </div>
  );
};

const KPIsPage: React.FC<{ shipments: Shipment[] }> = ({ shipments }) => {
  const [activeTab, setActiveTab] = useState<'Cargos in Transit' | 'Performance' | 'Operation Status'>('Cargos in Transit');
  const latestYear = useMemo(() => {
    const years = shipments.map((s) => { if (!s.actualEta) return null; const date = new Date(s.actualEta); return isNaN(date.getTime()) ? null : date.getFullYear(); }).filter((y) => y && !isNaN(y as number)) as number[];
    return years.length > 0 ? Math.max(...years) : new Date().getFullYear();
  }, [shipments]);
  const [filters, setFilters] = useState<KpiFilters>({ cargo: [], year: latestYear, month: 'All' });
  useEffect(() => { setFilters((f) => ({ ...f, year: latestYear })); }, [latestYear]);
  const handleFilterChange = (filterType: keyof KpiFilters, value: any) => { setFilters((prev) => ({ ...prev, [filterType]: value })); };

  const renderActiveDashboard = () => {
    switch (activeTab) {
      case 'Cargos in Transit': return <CargosInTransitDashboard shipments={shipments} onFilterChange={handleFilterChange} filters={filters} />;
