const PerformanceDashboard: React.FC<KPIPageProps> = ({ shipments, onFilterChange, filters }) => {
  const filteredShipments = useMemo(() => shipments.filter(s => {
    if (!s.diRegistrationDate) return false;
    const shipDate = new Date(s.diRegistrationDate);
    const yearMatch = filters.year === 'All' || shipDate.getFullYear() === filters.year;
    const monthMatch = filters.month === 'All' || shipDate.getMonth() === filters.month;
    const cargoMatch = !filters.cargo?.length || filters.cargo.includes(s.typeOfCargo || '');
    return yearMatch && monthMatch && cargoMatch;
  }), [shipments, filters]);

  const lineChartData = useMemo(() => {
    const months = Array(12).fill(null).map(() => ({ clearance: [] as number[], delivery: [] as number[], shipments: [] as Shipment[] }));
    filteredShipments.forEach(s => {
      const d = new Date(s.diRegistrationDate!);
      const m = d.getMonth();
      const clearance = calculateDaysBetween(s.cargoPresenceDate, s.greenChannelOrDeliveryAuthorizedDate);
      const delivery = calculateDaysBetween(s.greenChannelOrDeliveryAuthorizedDate, s.firstTruckDelivery);
      if (clearance !== null) months[m].clearance.push(clearance);
      if (delivery !== null) months[m].delivery.push(delivery);
      months[m].shipments.push(s);
    });
    const avg = (arr: number[]) => arr.length ? Math.round(arr.reduce((a, b) => a + b, 0) / arr.length) : 0;
    const labels = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    return {
      labels,
      clearance: months.map(m => ({ value: avg(m.clearance), shipments: m.shipments })),
      delivery: months.map(m => ({ value: avg(m.delivery), shipments: m.shipments }))
    };
  }, [filteredShipments]);

  return (
    <div>
      <KPIFilterSidebar shipments={shipments} onFilterChange={onFilterChange} activeFilters={filters} dateSourceField="diRegistrationDate" />
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>
        <LineChart title="Average Clearance Time" subtitle="Days from Presence to Green Channel" data={lineChartData.clearance} labels={lineChartData.labels} goal={5} color="#0891B2" />
        <LineChart title="Average Delivery Time" subtitle="Days from Clearance to First Truck" data={lineChartData.delivery} labels={lineChartData.labels} goal={3} color="#16A34A" />
      </div>
    </div>
  );
};

