interface DoughnutChartProps {
  title: string;
  data: { label: string; value: number; secondaryValue?: number; color: string; shipments: Shipment[]; }[];
  onSegmentClick?: ((title: string, shipments: Shipment[]) => void) | null;
  size?: number;
  strokeWidth?: number;
}

const DoughnutChart: React.FC<DoughnutChartProps> = ({ title, data, onSegmentClick = null, size = 180, strokeWidth = 20 }) => {
  const total = useMemo(() => data.reduce((sum, item) => sum + item.value, 0), [data]);
  const sortedData = useMemo(() => data.filter((d) => d.value > 0).sort((a, b) => b.value - a.value), [data]);
  const radius = size / 2 - strokeWidth;
  const circumference = 2 * Math.PI * radius;
  let offset = 0;

  return (
    <div className="chart-wrapper-full">
      {title && <h4>{title}</h4>}
      <div className="doughnut-chart-container">
        <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
          <circle className="doughnut-track" cx={size / 2} cy={size / 2} r={radius} strokeWidth={strokeWidth} fill="none" />
          {sortedData.map((item) => {
            const percentage = total > 0 ? item.value / total : 0;
            const segmentLength = circumference * percentage;
            const currentOffset = offset;
            offset += segmentLength;
            return <circle key={item.label} className="doughnut-segment" cx={size / 2} cy={size / 2} r={radius} strokeDasharray={`${segmentLength} ${circumference}`} strokeDashoffset={-currentOffset} stroke={item.color} strokeWidth={strokeWidth} fill="none" strokeLinecap="round" />;
          })}
          <text x={size / 2} y={size / 2} className="doughnut-total" dy=".3em" textAnchor="middle">{total}</text>
        </svg>
        <div className="doughnut-legend">
          {sortedData.map((item) => {
            const percentage = total > 0 ? ((item.value / total) * 100).toFixed(0) : 0;
            return (
              <button key={item.label} className="legend-button" onClick={() => onSegmentClick && onSegmentClick(item.label, item.shipments)} disabled={!onSegmentClick}>
                <div className="legend-group"><span className="legend-marker" style={{ backgroundColor: item.color }} /><span className="legend-label">{item.label}</span></div>
                <span className="legend-value">{item.value} ({percentage}%)</span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
};

