const LineChart: React.FC<LineChartProps> = ({ title, subtitle, data, labels, goal, color, onMaximize = null, onPointClick = null }) => {
  const [tooltip, setTooltip] = useState<any>(null);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const visibleData = useMemo(() => data, [data]);
  const visibleLabels = useMemo(() => labels, [labels]);

  const { width, height, margin } = useMemo(() => {
    const w = 400, h = 200;
    return { width: w - 50, height: h - 50, margin: { top: 20, right: 20, bottom: 30, left: 30 } };
  }, []);

  const { yScale, linePath, points } = useMemo(() => {
    if (!visibleData.length) return { linePath: '', points: [] };
    const yMax = Math.max(...visibleData.map(d => d.value), goal || 0) * 1.2 || 10;
    const xScaleFn = (i: number) => (i / (visibleData.length - 1 || 1)) * width;
    const yScaleFn = (v: number) => height - (v / yMax) * height;
    const line = visibleData.map((d, i) => `${i === 0 ? 'M' : 'L'} ${xScaleFn(i)} ${yScaleFn(d.value)}`).join(' ');
    const pts = visibleData.map((d, i) => ({ x: xScaleFn(i), y: yScaleFn(d.value), value: d.value, label: visibleLabels[i], shipments: d.shipments }));
    return { yScale: yScaleFn, linePath: line, points: pts };
  }, [visibleData, visibleLabels, width, height, goal]);

  return (
    <div className="chart-wrapper-full line-chart-card" onClick={() => onMaximize?.()} style={{ cursor: onMaximize ? 'pointer' : 'default' }}>
      <div style={{ marginBottom: '1rem' }}>
        <h4 style={{ margin: 0 }}>{title}</h4>
        <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', fontWeight: 700 }}>{subtitle}</p>
      </div>
      <div style={{ height: '180px' }} ref={containerRef}>
        <svg width="100%" height="100%" viewBox={`0 0 ${width + margin.left + margin.right} ${height + margin.top + margin.bottom}`}>
          <g transform={`translate(${margin.left},${margin.top})`}>
            <path d={linePath} fill="none" stroke={color} strokeWidth="3" />
            {points.map((p, i) => (
              <circle key={i} cx={p.x} cy={p.y} r="4" fill="white" stroke={color} strokeWidth="2" onClick={(e) => { e.stopPropagation(); onPointClick?.(p.label, p.shipments); }} />
            ))}
          </g>
        </svg>
      </div>
    </div>
  );
};

