const BrokerageKPIsPage: React.FC<{ shipments: Shipment[] }> = ({ shipments }) => {
  const [filters, setFilters] = useState({ analyst: 'All', month: 'All', year: 2025 as number | 'All', cargo: [] as string[], uniqueDi: 'All' });
  const [selectedShipments, setSelectedShipments] = useState<{ title: string; data: Shipment[]; } | null>(null);
  const handleFilterChange = (n: string, v: any) => setFilters(prev => ({ ...prev, [n]: v }));

  const filteredShipments = useMemo(() => shipments.filter(s => {
    if (!s.diRegistrationDate) return false;
    const shipDate = new Date(s.diRegistrationDate);
    const yearMatch = filters.year === 'All' || shipDate.getFullYear() === filters.year;
    const monthMatch = filters.month === 'All' || (shipDate.getMonth() + 1).toString().padStart(2, '0') === filters.month;
    const cargoMatch = !filters.cargo.length || filters.cargo.includes(s.typeOfCargo || '');
    return yearMatch && monthMatch && cargoMatch;
  }), [shipments, filters]);

  const diIndex = useMemo(() => buildUniqueDIIndex(filteredShipments), [filteredShipments]);
  const avgClearance = useMemo(() => {
    const times = filteredShipments.map(s => calculateDaysBetween(s.cargoPresenceDate, s.greenChannelOrDeliveryAuthorizedDate)).filter(v => v !== null);
    return times.length ? (times.reduce((a, b) => a + b, 0) / times.length).toFixed(1) : '0';
  }, [filteredShipments]);

  return (
    <div className="brokerage-kpi-page">
      <header className="kpi-page-header" style={{ marginBottom: '2rem' }}>
        <h1>Brokerage KPI Dashboard</h1>
        <h2>Performance Benchmarking</h2>
      </header>
      <BrokerageKPIFilter shipments={shipments} activeFilters={filters} onFilterChange={handleFilterChange} />
      <div className="kpi-grid">
        <KPIMetricCard icon={<span className="material-symbols-outlined">receipt_long</span>} title="Total DIs" value={diIndex.size} />
        <KPIMetricCard icon={<span className="material-symbols-outlined">payments</span>} title="Total Value" value={filteredShipments.reduce((s, d) => s + (d.invoiceValue || 0), 0).toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 })} />
        <KPIMetricCard icon={<span className="material-symbols-outlined">speed</span>} title="Avg Clearance" value={`${avgClearance}d`} />
        <KPIMetricCard icon={<span className="material-symbols-outlined">group</span>} title="Analysts" value={new Set(filteredShipments.map(s => s.technicianResponsibleBrazil)).size} />
      </div>
      {selectedShipments && <ShipmentsTable title={selectedShipments.title} shipments={selectedShipments.data} onClose={() => setSelectedShipments(null)} />}
    </div>
  );
};

