const App: React.FC = () => {
  const [user, setUser] = useState<firebase.User | null>(null);
  const [userData, setUserData] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [activePage, setActivePage] = useState('Dashboard');
  const [shipments, setShipments] = useState<Shipment[]>([]);
  const [dataLoading, setDataLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = auth.onAuthStateChanged(async (firebaseUser) => {
      if (firebaseUser) {
        setUser(firebaseUser);
        const userDoc = await firestore.collection('users').doc(firebaseUser.uid).get();
        if (userDoc.exists) { setUserData(userDoc.data() as User); } 
        else { setUserData({ id: firebaseUser.uid, name: firebaseUser.displayName || 'New User', username: firebaseUser.email || '', role: 'COMEX' }); }
      } else { setUser(null); setUserData(null); }
      setIsLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const fetchShipments = async () => {
      if (!user) return;
      setDataLoading(true);
      try {
        const snapshot = await firestore.collection('shipments').get();
        const shipmentsData = snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() } as Shipment));
        setShipments(shipmentsData);
      } catch (err) { console.error('Error fetching shipments:', err); } finally { setDataLoading(false); }
    };
    fetchShipments();
  }, [user]);

  if (isLoading) return <LoadingSpinner />;
  if (!user) return <LoginPage onLoginSuccess={() => {}} />;

  const navItems = [{ name: 'Dashboard', icon: 'dashboard' }, { name: 'Imports', icon: 'directions_boat' }, { name: 'KPIs', icon: 'bar_chart' }, { name: 'Brokerage KPIs', icon: 'pie_chart' }];

  return (
    <div className={'app-container ' + (isSidebarCollapsed ? 'sidebar-collapsed' : '')}>
      <aside className={'sidebar ' + (isSidebarCollapsed ? 'collapsed' : '')}>
        <header className="sidebar-header">
          <span>BYD</span>
        </header>
        <nav>
          <ul className="nav-links">
            {navItems.map((item) => (
              <li key={item.name}>
                <a href="#" className={'nav-link ' + (activePage === item.name ? 'active' : '')} onClick={(e) => { e.preventDefault(); setActivePage(item.name); }}>
                  <span className="material-symbols-outlined nav-icon">{item.icon}</span>
                  <span className="nav-label">{item.name}</span>
                </a>
              </li>
            ))}
          </ul>
        </nav>
        <footer className="sidebar-footer">
          <div className="user-info">
            <div style={{ width: '32px', height: '32px', borderRadius: '50%', background: '#DC2626', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 900 }}>{userData?.name?.charAt(0)}</div>
            <div className="user-details"><span className="user-name">{userData?.name?.split(' ')[0]}</span><span className="user-role">{userData?.role}</span></div>
          </div>
        </footer>
      </aside>
      <main className="main-content">
        {activePage === 'Dashboard' && <DashboardPage shipments={shipments} onNavigate={(p) => setActivePage(p)} user={userData} />}
        {activePage === 'KPIs' && <KPIsPage shipments={shipments} />}
        {activePage === 'Brokerage KPIs' && <BrokerageKPIsPage shipments={shipments} />}
        {activePage === 'Imports' && <ImportsPage shipments={shipments} isLoading={dataLoading} error={""} onUpload={async () => {}} />}
      </main>
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);
